import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
} from 'chart.js';
import { Line } from 'react-chartjs-2';
import '../styles/GraphsOfChanges.css';

// Реєструємо компоненти Chart.js
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

function GraphsOfChanges() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [healthData, setHealthData] = useState([]);
  const [selectedIndicators, setSelectedIndicators] = useState([]);
  const [error, setError] = useState('');

  const indicators = [
    { id: 'FEV1', label: 'FEV1' },
    { id: 'FVC', label: 'FVC' },
    { id: 'PEF', label: 'PEF' },
    { id: 'respiratory_rate', label: 'Respiratory Rate' },
    { id: 'pulse', label: 'Pulse' },
    { id: 'cough', label: 'Cough' },
    { id: 'breathlessness', label: 'Breathlessness' },
    { id: 'wheezing', label: 'Wheezing' },
    { id: 'chest_tightness', label: 'Chest Tightness' },
    { id: 'nighttime_awakenings', label: 'Nighttime Awakenings' }
  ];

  useEffect(() => {
    fetchHealthData();
  }, []);

  const fetchHealthData = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch health records');
      }
      const data = await response.json();
      setHealthData(data.sort((a, b) => new Date(a.date) - new Date(b.date)));
    } catch (error) {
      console.error('Error fetching health records:', error);
      setError('Failed to load health records');
    }
  };

  const handleIndicatorChange = (indicatorId) => {
    setSelectedIndicators(prev => {
      if (prev.includes(indicatorId)) {
        return prev.filter(id => id !== indicatorId);
      } else {
        return [...prev, indicatorId];
      }
    });
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  const getChartData = () => {
    const labels = healthData.map(record => {
      const date = new Date(record.date);
      return date.toLocaleDateString();
    });

    const datasets = selectedIndicators.map(indicator => ({
      label: indicators.find(i => i.id === indicator)?.label || indicator,
      data: healthData.map(record => record[indicator]),
      borderColor: `hsl(${Math.random() * 360}, 70%, 50%)`,
      tension: 0.1
    }));

    return {
      labels,
      datasets
    };
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Health Indicators Over Time'
      }
    },
    scales: {
      y: {
        beginAtZero: true
      }
    }
  };

  return (
    <div className={`graphs-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={() => navigate('/profile')} className="profile-button">
            Profile
          </button>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className="content">
        <h2>Graphs of Changes</h2>
        {error && <div className="error-message">{error}</div>}
        
        <div className="indicators-selection">
          <h3>Select Indicators:</h3>
          <div className="indicators-grid">
            {indicators.map(indicator => (
              <label key={indicator.id} className="indicator-checkbox">
                <input
                  type="checkbox"
                  checked={selectedIndicators.includes(indicator.id)}
                  onChange={() => handleIndicatorChange(indicator.id)}
                />
                {indicator.label}
              </label>
            ))}
          </div>
        </div>

        <div className="graph-container">
          {selectedIndicators.length > 0 ? (
            <Line data={getChartData()} options={chartOptions} />
          ) : (
            <div className="no-indicators">
              Please select at least one indicator to display the graph
            </div>
          )}
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default GraphsOfChanges;
